import{_ as a,o as i,c as o,ai as r}from"./chunks/framework.ampVZV4B.js";const _=JSON.parse('{"title":"01 本地部署：Ollama / vLLM / LM Studio 怎么选，怎么跑","description":"","frontmatter":{},"headers":[],"relativePath":"ai/model-deploy/01-local-deploy.md","filePath":"ai/model-deploy/01-local-deploy.md"}'),e={name:"ai/model-deploy/01-local-deploy.md"};function t(n,l,s,d,h,u){return i(),o("div",null,[...l[0]||(l[0]=[r('<h1 id="_01-本地部署-ollama-vllm-lm-studio-怎么选-怎么跑" tabindex="-1">01 本地部署：Ollama / vLLM / LM Studio 怎么选，怎么跑 <a class="header-anchor" href="#_01-本地部署-ollama-vllm-lm-studio-怎么选-怎么跑" aria-label="Permalink to “01 本地部署：Ollama / vLLM / LM Studio 怎么选，怎么跑”">​</a></h1><blockquote><p>目标：用最小成本把模型在本地跑起来，优先满足“写代码/写文档/本地知识库问答”的日常需求。</p></blockquote><h2 id="_1-本地部署适合什么场景" tabindex="-1">1）本地部署适合什么场景 <a class="header-anchor" href="#_1-本地部署适合什么场景" aria-label="Permalink to “1）本地部署适合什么场景”">​</a></h2><ul><li><strong>隐私优先</strong>：不希望把笔记/代码发到云端</li><li><strong>弱网/断网也能用</strong></li><li><strong>成本可控</strong>：少量调用、长期使用</li><li><strong>延迟可控</strong>：同机推理通常更稳定</li></ul><p>不太适合：</p><ul><li>你需要很强推理/长上下文/高并发（本机会吃不消）</li></ul><h2 id="_2-三种本地部署路线-怎么选" tabindex="-1">2）三种本地部署路线（怎么选） <a class="header-anchor" href="#_2-三种本地部署路线-怎么选" aria-label="Permalink to “2）三种本地部署路线（怎么选）”">​</a></h2><h3 id="_2-1-ollama-最省心" tabindex="-1">2.1 Ollama（最省心） <a class="header-anchor" href="#_2-1-ollama-最省心" aria-label="Permalink to “2.1 Ollama（最省心）”">​</a></h3><ul><li><strong>适合</strong>：快速上手、本地小模型、日常问答/总结/写作</li><li><strong>优点</strong>：安装简单、模型管理方便、生态成熟</li><li><strong>缺点</strong>：极限性能不如专业推理引擎，深度定制能力有限</li></ul><h3 id="_2-2-vllm-偏工程化-性能" tabindex="-1">2.2 vLLM（偏工程化/性能） <a class="header-anchor" href="#_2-2-vllm-偏工程化-性能" aria-label="Permalink to “2.2 vLLM（偏工程化/性能）”">​</a></h3><ul><li><strong>适合</strong>：你想把本地模型做成“服务”，后续接 Agent/MVP Server</li><li><strong>优点</strong>：吞吐与服务化能力更强（尤其在 GPU 环境）</li><li><strong>缺点</strong>：部署与参数更工程化，上手成本更高</li></ul><h3 id="_2-3-lm-studio-偏桌面端体验" tabindex="-1">2.3 LM Studio（偏桌面端体验） <a class="header-anchor" href="#_2-3-lm-studio-偏桌面端体验" aria-label="Permalink to “2.3 LM Studio（偏桌面端体验）”">​</a></h3><ul><li><strong>适合</strong>：你希望“可视化管理模型 + 本地聊天”快速使用</li><li><strong>优点</strong>：界面友好，上手快</li><li><strong>缺点</strong>：更偏个人使用，不太像服务端组件</li></ul><h2 id="_3-本地部署的关键约束-先看再装" tabindex="-1">3）本地部署的关键约束（先看再装） <a class="header-anchor" href="#_3-本地部署的关键约束-先看再装" aria-label="Permalink to “3）本地部署的关键约束（先看再装）”">​</a></h2><ul><li><strong>硬件</strong>： <ul><li>CPU 能跑，但速度会慢</li><li>有 GPU（尤其显存大）体验更好</li></ul></li><li><strong>模型大小</strong>： <ul><li>先从“小模型”开始，能跑通闭环比追求大模型更重要</li></ul></li><li><strong>上下文长度</strong>： <ul><li>知识库问答/长文摘要更吃上下文与显存</li></ul></li></ul><h2 id="_4-本地使用的推荐姿势-配合你的知识库" tabindex="-1">4）本地使用的推荐姿势（配合你的知识库） <a class="header-anchor" href="#_4-本地使用的推荐姿势-配合你的知识库" aria-label="Permalink to “4）本地使用的推荐姿势（配合你的知识库）”">​</a></h2><ul><li><strong>个人学习/面试</strong>： <ul><li>先本地跑一个可用模型</li><li>用你阶段一/二的脚本，把 <code>docs/</code> 里的内容喂给模型做总结/出题</li></ul></li><li><strong>RAG/Agent</strong>（后续）： <ul><li>本地模型作为推理层</li><li><code>MVP Server</code> 作为“上下文提供层”</li></ul></li></ul><h2 id="_5-最小验收-今天就能完成" tabindex="-1">5）最小验收（今天就能完成） <a class="header-anchor" href="#_5-最小验收-今天就能完成" aria-label="Permalink to “5）最小验收（今天就能完成）”">​</a></h2><ul><li>你能在本地跑通一次：输入一段 Markdown → 输出固定模板总结</li><li>你能记录下 3 个指标： <ul><li>速度（体感/耗时）</li><li>稳定性（是否容易崩/卡）</li><li>成本（本地=硬件成本 vs 云端=调用成本）</li></ul></li></ul>',19)])])}const g=a(e,[["render",t]]);export{_ as __pageData,g as default};
